info:
프론트엔드에서 제어 버튼 클릭 → API Gateway → Lambda → IoT Core MQTT publish → 이 노드에서 수신

토픽 패턴: smartfarm/{house_id}/{device_id}/control
페이로드: { command, timestamp, house_id, window_id, operator, request_id }

func:
// MQTT 토픽에서 장치 ID 추출
// 토픽: smartfarm/house1/window1/control
const topicParts = msg.topic.split('/');
const houseId = topicParts[1] || 'unknown';
const deviceId = topicParts[2] || 'unknown';

// 페이로드 파싱
const payload = msg.payload;
const command = payload.command || 'unknown';
const operator = payload.operator || 'unknown';
const requestId = payload.request_id || '';
const timestamp = payload.timestamp || new Date().toISOString();

// 장치 유형 판별
let deviceType = 'unknown';
if (deviceId.startsWith('window')) deviceType = 'window';
else if (deviceId.startsWith('fan')) deviceType = 'fan';
else if (deviceId.startsWith('heater')) deviceType = 'heater';
else if (deviceId.startsWith('valve')) deviceType = 'valve';

// 메시지에 파싱 결과 첨부
msg.control = {
    houseId,
    deviceId,
    deviceType,
    command,
    operator,
    requestId,
    timestamp,
    raw: payload
};

const cmdLabels = {
    open: '열기', close: '닫기', stop: '정지',
    on: 'ON', off: 'OFF'
};
const label = cmdLabels[command] || command;

node.status({
    fill: 'green',
    shape: 'dot',
    text: `${label} ← ${houseId}/${deviceId} (${operator})`
});

node.warn(`📥 제어 수신: ${houseId}/${deviceId} ${command.toUpperCase()} by ${operator} [${requestId}]`);

return msg;

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// 실제 장치 제어 로직
// GPIO, 릴레이 모듈 등을 여기서 제어
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

const { deviceId, deviceType, command } = msg.control;

// GPIO 핀 매핑 (예시 - 실제 하드웨어에 맞게 수정)
const GPIO_MAP = {
    'window1': { open: 17, close: 27 },  // GPIO 17=열기, 27=닫기
    'window2': { open: 22, close: 23 },
    'fan1':    { on: 24, off: 24 },       // 같은 핀 HIGH/LOW
    'heater1': { on: 25, off: 25 },
    'valve1':  { open: 5, close: 6 },
};

const pins = GPIO_MAP[deviceId];

if (!pins) {
    node.warn(`⚠️ ${deviceId}: GPIO 매핑 없음 (시뮬레이션 모드)`);
    node.status({ fill: 'yellow', shape: 'ring', text: `시뮬레이션: ${deviceId} ${command}` });

    // 시뮬레이션 - 실제 GPIO 없이 성공 처리
    msg.control.executed = true;
    msg.control.simulated = true;
    return msg;
}

// TODO: 실제 GPIO 제어 코드
// const Gpio = require('onoff').Gpio;
// 또는 exec('gpio write ...')

try {
    // 장치 유형별 제어
    switch (deviceType) {
        case 'window':
        case 'valve':
            if (command === 'open') {
                // GPIO pins.open HIGH, pins.close LOW
                node.warn(`🔓 ${deviceId} 열기: GPIO ${pins.open} HIGH`);
            } else if (command === 'close') {
                // GPIO pins.close HIGH, pins.open LOW
                node.warn(`🔒 ${deviceId} 닫기: GPIO ${pins.close} HIGH`);
            } else if (command === 'stop') {
                // 모두 LOW
                node.warn(`⛔ ${deviceId} 정지: GPIO ALL LOW`);
            }
            break;

        case 'fan':
        case 'heater':
            if (command === 'on') {
                node.warn(`⚡ ${deviceId} ON: GPIO ${pins.on} HIGH`);
            } else if (command === 'off') {
                node.warn(`🔌 ${deviceId} OFF: GPIO ${pins.off} LOW`);
            }
            break;
    }

    msg.control.executed = true;
    msg.control.simulated = false;
    node.status({ fill: 'green', shape: 'dot', text: `실행: ${deviceId} ${command}` });

} catch (error) {
    msg.control.executed = false;
    msg.control.error = error.message;
    node.status({ fill: 'red', shape: 'dot', text: `실패: ${error.message}` });
    node.error(`❌ 제어 실행 실패: ${error.message}`);
}

return msg;

// 제어 응답을 IoT Core로 전송
// 프론트엔드에서 이 토픽을 구독하면 실시간 상태 확인 가능

const { houseId, deviceId, command, requestId, operator } = msg.control;

msg.topic = `smartfarm/${houseId}/${deviceId}/response`;
msg.payload = {
    request_id: requestId,
    house_id: houseId,
    device_id: deviceId,
    command: command,
    status: 'received',
    operator: operator,
    executed_at: new Date().toISOString(),
    device_client: 'MyFarmPi_01'
};

node.status({
    fill: 'blue',
    shape: 'dot',
    text: `응답 → ${msg.topic}`
});

return msg;
